	constructor() {
		classes(() => [
			this.link() === undefined ? 'cursor-pointer' : '',
			buttonVariants({
				variant: this.isActive() ? 'outline' : 'ghost',
				size: this.size(),
			}),
		]);
	}
}

@Component({
	selector: 'hlm-pagination-next',
	imports: [HlmPaginationLink, NgIcon, HlmIcon],
